+                    {
+                        attrs.insert("weight".to_owned(), CgseValue::Float(weight));
+                    }
+
+                    // For *Edges, add both directions
+                    if section == PajekSection::Edges {
+                        let _ = graph.add_edge_with_attrs(&src_label, &dst_label, attrs.clone());
